 cipher info setup, name: %s, block size: %d
&quot;, mbedtls_cipher_get_name(&amp;ctx), mbedtls_cipher_get_block_size(&amp;ctx)); mbedtls_cipher_setkey(&amp;ctx, key, sizeof(key)*8, MBEDTLS_ENCRYPT); mbedtls_cipher_set_iv(&amp;ctx, iv, sizeof(iv)); mbedtls_cipher_update(&amp;ctx, ptx, strlen(ptx), buf, &amp;len); olen += len; mbedtls_cipher_finish(&amp;ctx, buf + len, &amp;len); olen += len; dump_buf(&quot;
 cipher aes encrypt:&quot;, buf, olen); mbedtls_cipher_free(&amp;ctx); &#125; int main(void) &#123; cipher(MBEDTLS_CIPHER_AES_128_CBC); cipher(MBEDTLS_CIPHER_AES_128_CTR); return 0; &#125; 与单向散列函数计算过程相似，这里使用setkey和setiv代替start，而update可以多次调用形成数据流，在目标板内存受限时减小资源的压力，finish函数则可以结束运算。 mbedtls_config.h#ifndef MBEDTLS_CONFIG_H #define MBEDTLS_CONFIG_H /* System support */ #define MBEDTLS_PLATFORM_C #define MBEDTLS_PLATFORM_MEMORY #define MBEDTLS_MEMORY_BUFFER_ALLOC_C #define MBEDTLS_PLATFORM_NO_STD_FUNCTIONS #define MBEDTLS_PLATFORM_EXIT_ALT #define MBEDTLS_NO_PLATFORM_ENTROPY #define MBEDTLS_NO_DEFAULT_ENTROPY_SOURCES #define MBEDTLS_PLATFORM_PRINTF_ALT /* mbed TLS modules */ #define MBEDTLS_AES_C #define MBEDTLS_CIPHER_C #define MBEDTLS_CIPHER_MODE_CBC #define MBEDTLS_CIPHER_MODE_CTR #define MBEDTLS_CIPHER_MODE_WITH_PADDING #define MBEDTLS_CIPHER_PADDING_PKCS7 #define MBEDTLS_AES_ROM_TABLES #include &quot;mbedtls/check_config.h&quot; #endif /* MBEDTLS_CONFIG_H */ CMakeLists.txtcmake_minimum_required(VERSION 3.8) project(&quot;aes&quot;) include_directories(./ $ENV&#123;MBEDTLS_BASE&#125;/include) aux_source_directory($ENV&#123;MBEDTLS_BASE&#125;/library MBEDTLS_SOURCES) set(SOURCES $&#123;CMAKE_CURRENT_LIST_DIR&#125;/main.c $&#123;CMAKE_CURRENT_LIST_DIR&#125;/mbedtls_config.h $&#123;MBEDTLS_SOURCES&#125;) add_executable(aes $&#123;SOURCES&#125;) 运行结果： mkdir -p build &amp;&amp; cd build &amp;&amp; cmake .. &amp;&amp; make -j32 ./aes cipher info setup, name: AES-128-CBC, block size: 16 cipher aes encrypt: 4D DF 90 12 D7 B3 89 87 45 A1 ED 98 60 EB 0F A2 FD 2B BD 80 D2 71 90 D7 2A 2F 24 0C 8F 37 2A 27 63 74 62 96 DD C2 BF CE 7C 25 2B 6C D7 DD 4B A8 57 7E 09 6D BD 80 24 C8 B4 C5 A1 16 0C A2 D3 F9 cipher info setup, name: AES-128-CTR, block size: 16 cipher aes encrypt: C4 1A 1D B1 56 C0 9B 59 E8 25 D9 5B 72 FD 97 BE F7 06 BA C1 B8 4F F5 4E 72 88 2D 17 0B DB 53 0A 9B 0A FD 86 41 65 73 06 6B C1 F0 52 18 FC 1D 57 9D F4 81 F7 08 CB cipher相关结构体typedef struct mbedtls_cipher_context_t &#123; /** Information about the associated cipher. */ const mbedtls_cipher_info_t *cipher_info; /** Key length to use. */ int key_bitlen; /** Operation that the key of the context has been * initialized for. */ mbedtls_operation_t operation; #if defined(MBEDTLS_CIPHER_MODE_WITH_PADDING) /** Padding functions to use, if relevant for * the specific cipher mode. */ void (*add_padding)( unsigned char *output, size_t olen, size_t data_len ); int (*get_padding)( unsigned char *input, size_t ilen, size_t *data_len ); #endif /** Buffer for input that has not been processed yet. */ unsigned char unprocessed_data[MBEDTLS_MAX_BLOCK_LENGTH]; /** Number of Bytes that have not been processed yet. */ size_t unprocessed_len; /** Current IV or NONCE_COUNTER for CTR-mode, data unit (or sector) number * for XTS-mode. */ unsigned char iv[MBEDTLS_MAX_IV_LENGTH]; /** IV size in Bytes, for ciphers with variable-length IVs. */ size_t iv_size; /** The cipher-specific context. */ void *cipher_ctx; #if defined(MBEDTLS_CMAC_C) /** CMAC-specific context. */ mbedtls_cmac_context_t *cmac_ctx; #endif #if defined(MBEDTLS_USE_PSA_CRYPTO) /** Indicates whether the cipher operations should be performed * by Mbed TLS&#x27; own crypto library or an external implementation * of the PSA Crypto API. * This is unset if the cipher context was established through * mbedtls_cipher_setup(), and set if it was established through * mbedtls_cipher_setup_psa(). */ unsigned char psa_enabled; #endif /* MBEDTLS_USE_PSA_CRYPTO */ &#125; mbedtls_cipher_context_t; typedef struct mbedtls_cipher_info_t &#123; /** Full cipher identifier. For example, * MBEDTLS_CIPHER_AES_256_CBC. */ mbedtls_cipher_type_t type; /** The cipher mode. For example, MBEDTLS_MODE_CBC. */ mbedtls_cipher_mode_t mode; /** The cipher key length, in bits. This is the * default length for variable sized ciphers. * Includes parity bits for ciphers like DES. */ unsigned int key_bitlen; /** Name of the cipher. */ const char * name; /** IV or nonce size, in Bytes. * For ciphers that accept variable IV sizes, * this is the recommended size. */ unsigned int iv_size; /** Bitflag comprised of MBEDTLS_CIPHER_VARIABLE_IV_LEN and * MBEDTLS_CIPHER_VARIABLE_KEY_LEN indicating whether the * cipher supports variable IV or variable key sizes, respectively. */ int flags; /** The block size, in Bytes. */ unsigned int block_size; /** Struct for base cipher information and functions. */ const mbedtls_cipher_base_t *base; &#125; mbedtls_cipher_info_t; 5 公钥密码 密钥配送问题解决方法： 事先共享 密钥分配中心KDC 密钥交换 公钥密码 接收者将公钥发送给发送者，发送者使用公钥加密后将密文传递给接收者，接收者使用对应的私钥进行解密 公钥密码存在的问题，公钥认证问题，中间人攻击：窃听者给发送者错误的公钥并获取明文，再将明文篡改后使用正确的公钥加密返回给接收者从而实现攻击 RSA算法 $$密文=明文^E mod N,(E,N)是公钥\明文=密文^D mod N,(D,N)是私钥$$ 算法：生成密钥对，准备两个很大的质数p和q $$N=pq\L=lcm(p-1,q-1),lcm表示求最小公倍数\1&lt;E&lt;L,gcd(E,L) = 1,gcd表示求最大公约数（使用辗转相除法）\1&lt;D&lt;L,EDmodL=1$$ RSA攻击方法：一旦发现了对大整数进行质因数分解的高效算法， RSA 就能够被破译 中间人攻击 选择密文攻击–RSA-OAEP 其他公钥密码 EIGamal Rabin ECC，椭圆曲线加密 6 混合密码系统 背景： 公钥密码不足：计算效率低，但可以解决密钥配送问题 对称密码不足：密钥配送麻烦，但是速度快 混合密码系统 概念：使用公钥密码保护对称密码密钥 加密过程：明文使用对称密码密钥加密，对称密码密钥使用公钥加密，两者发送给接收者 解密过程：对称密码密钥使用私钥解密，密文使用对称密码密钥解密 7 单向散列函数 文件、密文是否被篡改：完整性、一致性，integrity 单向散列函数有一个输入和输出，输入称为消息，输出称为散列值 根据任意长度的消息计算出固定长度的散列值，无论消息的长度如何，散列值的大小应当不变 能够快速计算出散列值 消息不同散列值也不同，理论上消息变化一个比特，散列值应当有明显变化以确定消息是否被篡改 两个不同的消息产生同一个散列值的情况称为碰撞(collision )，难以发现碰撞的性质称为抗碰撞性(collision resistance) 单向散列函数必须确保要找到和该条消息具有相同散列值的另外一条消息是非常困难的。这一性质称为弱抗碰撞性。单向散列函数都必须具备弱抗碰撞性。 强抗碰撞性。所谓强抗碰撞性，是指要找到散列值相同的两条不同的消息是非常困难的这一性质。在这里，散列值可以是任意值。 单向散列函数必须具备单向性(one-way )。单向性指的是无法通过散列值反算出消息的性质。 单向散列函数又称为哈希函数 实际应用 检测软件是否被篡改 基于口令的加密 消息认证码 数字签名 伪随机数生成器 一次性口令 常见的单向散列函数 MD4、MD5，强对抗性已被攻破 SHA-1，不安全 SHA-256、SHA-384、SHA-521（SHA-2） RIPEMD-160 SHA-3：Keccak算法 对单向散列函数的攻击 暴力破解，针对弱抗碰撞性 先准备两个散列值相同的不同消息，针对强抗碰撞性 单向散列函数无法解决的问题 无法验证伪装，只能识别是否篡改 使用认证技术可以识破伪装，认证技术包括消息验证码和数字签名 原理满足密码学算法安全属性的特殊散列函数，保证数据的完整性，抵御篡改攻击，原数据称作消息，计算后的输出称为摘要，在通信中，Bob接受Alice发来的消息及摘要，通过相同的算法计算摘要比对以验证消息是否被篡改。 性质输入长度可变，输出长度固定，计算过程应当高效率，具备单向性。 抗弱碰撞性，对于给定$a$，能找到$b$使得$h(a)=h(b)$不可行 抗强碰撞性，给定一个输出$z$，能够找到$h(a)=z$不可行 应用消息完整性检测、伪随机数生成器、数字签名、消息认证码 MD算法 MD4：散列碰撞已被攻破 MD5：抗碰撞性已被攻破 SHA算法SHA0/SHA1不再使用 SHA2：包括SHA256，SHA384，SHA512 SHA3：更为安全 SHA256处理步骤： 预处理 消息填充 消息分割 设置初始摘要值 $H^{(0)}$ 准备常量$K^{256}_{i}$ 哈希计算 消息调度 初始化工作寄存器 更新工作寄存器 计算消息摘要 generic_sum计算散列值 generic_sum SHA256 &lt;file name&gt; 头文件和函数接口#include &quot;mbedtls/md.h&quot; 接口 描述 mbedtls_md_init 初始化md结构体 mbedtls_md_info_from_type 根据算法类型得到md信息结构体指针 mbedtls_md_setup 初始化md结构体 mbedtls_md_get_name 获得单向散列算法名称 mbedtls_md_get_size 获取单向散列算法输出消息摘要长度 mbedtls_md_starts md启动接口 mbedtls_md_update md更新接口，处理输入数据，包括预处理和计算 mbedtls_md_finish md输出消息摘要结果 mbedtls_md_free 释放md结构体 依赖#define MBEDTLS_MD_C #define MBEDTLS_SHA256_C 散列示例代码#include &lt;stdio.h&gt; #include &lt;string.h&gt; #include &lt;stdint.h&gt; #include &quot;mbedtls/md.h&quot; #include &quot;mbedtls/platform.h&quot; static void dump_buf(char *info, uint8_t *buf, uint32_t len) &#123; mbedtls_printf(&quot;%s&quot;, info); for (int i = 0; i &lt; len; i++) &#123; mbedtls_printf(&quot;%s%02X%s&quot;, i % 16 == 0 ? &quot;
	&quot;:&quot; &quot;, buf[i], i == len - 1 ? &quot;
