cipher info setup, name: %s, block size: %d
&quot;, mbedtls_cipher_get_name(&amp;ctx), mbedtls_cipher_get_block_size(&amp;ctx)); mbedtls_cipher_setkey(&amp;ctx, key, sizeof(key) * 8, MBEDTLS_ENCRYPT); mbedtls_cipher_set_iv(&amp;ctx, iv, sizeof(iv)); mbedtls_cipher_update(&amp;ctx, ptx, strlen(ptx), buf, &amp;len); olen += len; mbedtls_cipher_finish(&amp;ctx, buf + len, &amp;len); olen += len; dump_buf(&quot;
cipher aes encrypt:&quot;, buf, olen); mbedtls_cipher_free(&amp;ctx); &#125; void hardware_init(void) &#123; // fpioa映射 fpioa_set_function(PIN_UART_USB_RX, FUNC_UART_USB_RX); fpioa_set_function(PIN_UART_USB_TX, FUNC_UART_USB_TX); &#125; int main(void) &#123; hardware_init(); // 初始化串口3，设置波特率为115200 uart_init(UART_USB_NUM); uart_configure(UART_USB_NUM, 115200, UART_BITWIDTH_8BIT, UART_STOP_1, UART_PARITY_NONE); char *info = &#123;&quot;This is AES test on K210 RISC-V!
&quot;&#125;; uart_send_data(UART_USB_NUM, info, strlen(info)); cipher(MBEDTLS_CIPHER_AES_128_CBC); cipher(MBEDTLS_CIPHER_AES_128_CTR); while(1) &#123; &#125; return 0; &#125; pin_config.h #ifndef _PIN_CONFIG_H_ #define _PIN_CONFIG_H_ /*****************************HEAR-FILE************************************/ #include &quot;fpioa.h&quot; #include &quot;uart.h&quot; /*****************************HARDWARE-PIN*********************************/ // 硬件IO口，与原理图对应 #define PIN_UART_USB_RX (4) #define PIN_UART_USB_TX (5) /*****************************SOFTWARE-GPIO********************************/ // 软件GPIO口，与程序对应 #define UART_USB_NUM UART_DEVICE_3 /*****************************FUNC-GPIO************************************/ // GPIO口的功能，绑定到硬件IO口 #define FUNC_UART_USB_RX (FUNC_UART1_RX + UART_USB_NUM * 2) #define FUNC_UART_USB_TX (FUNC_UART1_TX + UART_USB_NUM * 2) #endif /* _PIN_CONFIG_H_ */ 在sdk下新建build文件夹并进入： cmake .. -DPROJ=test_mbedtls -G &quot;MinGW Makefiles&quot; 将编译好的文件烧入开发板中 上电运行：demo运行成功。

CMake为源码提供多项目的支持，是非常好的跨平台编译器。 但是这工具随着版本更新，越来越冗杂，社区也提出modern CMake帮助用户更好的使用cmake。当构建的项目复杂到一定程序时，维护CMake将变得非常不便，本帖将从最简单的功能出发，一步步建立起CMake架构，希望对你能有所帮助。 安装官网下载：Cmake sudo apt-get install cmake make cmake --version cmake学习参考： 官方文档：Cmake documentation wiki：wiki 博客：Linux下CMake简明教程 cmake examples，很好的新手教程，下载： git clone git@github.com:ttroy50/cmake-examples.git OK, let’s start ! 注：本文不使用link_libraries这类不带target前缀的函数，后者通常在add_executable之后加入，前者可以任意地方引入，尽管前者更为简单，但是不能对多类目标构建清晰的结构，新版本的CMake建议使用target前缀的函数。 基础功能第一个Cmake项目CMakeLists.txt如下，功能十分简单，设置最低版本要求，新建project，增加从源码编译可执行文件的规则。 # Set the minimum version of CMake that can be used # To find the cmake version run # $ cmake --version cmake_minimum_required(VERSION 3.5) # Set the project name project (hello_cmake) # set (EXECUTABLE_OUTPUT_PATH $&#123;PROJECT_SOURCE_DIR&#125;/bin) # Add an executable add_executable(hello_cmake main.cpp) 编译： mkdir build &amp;&amp; cd build cmake .. &amp;&amp; make -j4 我们可以通过下面命令将可执行文件重定向到bin目录下： set (EXECUTABLE_OUTPUT_PATH $&#123;PROJECT_SOURCE_DIR&#125;/bin) 增加头文件通常头文件放在include目录下，源码放在src下，main文件放在src的一级目录，函数文件可以继续递归放置： . ├── CMakeLists.txt ├── include │ └── Hello.h └── src ├── Hello.cpp └── main.cpp 看一下CMakeLists.txt，新建一个SOURCE的变量（在多源码情况下可以建立多个不同的名称），该变量的值为一个“数组”，接下来在生成可执行文件函数add_executable中使用该变量，在多个变量情况下可以在末尾继续添加，也可以使用file命令file(GLOB SOURCES &quot;src/*.cpp&quot;)通过搜索通配符添加，也可以使用aux_source_directory(src SOURCES)添加。最后链接头文件，使用target_include_directories函数，该函数第一个变量是目标target，这里指可执行文件，之后是PRIVATE|PUBLIC|INTERFACE，顾名思义这是指作用域，之后再解释，最后一个参数是路径，用PROJECT_SOURCE_DIR指向路径。 cmake_minimum_required(VERSION 3.5) project (hello_headers) # Create a sources variable with a link to all cpp files to compile set(SOURCES src/Hello.cpp src/main.cpp ) # file(GLOB SOURCES &quot;src/*.cpp&quot;) # aux_source_directory(src SOURCES) # Add an executable with the above sources add_executable(hello_headers $&#123;SOURCES&#125;) # Set the directories that should be included in the build command for this target # when running g++ these will be included as -I/directory/path/ target_include_directories(hello_headers PRIVATE $&#123;PROJECT_SOURCE_DIR&#125;/include ) 生成静态库静态库给其他程序编译时使用并全部编译进可执行程序，因此在程序运行时不需要链接，后缀为.a。 . ├── build ├── CMakeLists.txt ├── src │ ├── Hello.cpp # 库的头文件 │ └── main.cpp ├── src │ └── Hello.cpp # 库的接口文件 └── static_libs └── libhello_library.a CMakeLists.txt，生成静态库，通过add_library函数导入库源码，第一个参数时target，这里是库名称xxx，最后生成的也是libxxx.a，第二个参数是类型STATIC|SHARED|MODULE，第三个参数是源文件。使用target_include_directories函数为目标链接头文件。这里PUBLIC|PRIVATE|INTERFACE区别如下： PRIVATE - the directory is added to this target’s include directories，只给库自己调用，或者外部引用库的程序使用 INTERFACE - the directory is added to the include directories for any targets that link this library，可以给外部的或者内部其他目标使用 PUBLIC - As above, it is included in this library and also any targets that link this library，同上，但只导出符号 cmake_minimum_required(VERSION 3.5) project(hello_library) set(LIBRARY_OUTPUT_PATH $&#123;PROJECT_SOURCE_DIR&#125;/static_libs) # 重定向输出目录 #Generate the static library from the library sources add_library(hello_library STATIC src/Hello.cpp ) target_include_directories(hello_library PUBLIC $&#123;PROJECT_SOURCE_DIR&#125;/include ) 编译后在static_libs下面生成了静态库。让我们在这个project内部使用这个静态库，使用target_link_libraries函数为可执行文件目标添加静态库。这里的范围关键字参考CMake target_link_libraries Interface Dependencies # Add an executable with the above sources add_executable(hello_binary src/main.cpp ) # link the new hello_library target with the hello_binary target target_link_libraries( hello_binary PRIVATE hello_library ) 注意：在main.cpp中必须设置正确的头文件路径： #include &quot;static/Hello.h&quot; 在外部程序中如何使用静态库？可以将库文件和头文件拷贝到新的project中，这里注意库和新的可执行文件的编译工具需要相同。 . ├── build ├── CMakeLists.txt ├── include │ └── Hello.h ├── libs │ └── libhello_library.a └── src └── main.cpp cmake_minimum_required(VERSION 3.5) project(test_libs) # set(CMAKE_C_COMPILER &quot;arm-none-eabi-gcc&quot;) # set(CMAKE_CXX_COMPILER &quot;arm-none-eabi-g++&quot;) # Add an executable with the above sources add_executable(hello_binary src/main.cpp ) # link the new hello_library target with the hello_binary target target_link_libraries( hello_binary PRIVATE $&#123;PROJECT_SOURCE_DIR&#125;/libs/libhello_library.a ) target_include_directories(hello_binary PRIVATE $&#123;PROJECT_SOURCE_DIR&#125;/include ) 这里target_link_libraries函数在使用时，既可以是具体的库文件目录也可以是系统中安装的库。我们的库是使用gcc编译的，如果将上面CMakeLists.txt文件中打开交叉编译工具，则将无法编译通过。 生成动态库动态库不会编译到程序中，因此可执行文件体积较小，但是运行时需要链接动态库。动态库的后缀为.so，可以方便库函数的升级而不需要升级程序本体。 . ├── build ├── CMakeLists.txt ├── include │ └── shared │ └── Hello.h ├── README.adoc └── src ├── Hello.cpp └── main.cpp CMakeLists.txt cmake_minimum_required(VERSION 3.5) project(hello_library) ############################################################ # Create a library ############################################################ #Generate the shared library from the library sources add_library(hello_library SHARED src/Hello.cpp ) add_library(hello::library ALIAS hello_library) # ALIAS关键字，内部重命名 target_include_directories(hello_library PUBLIC $&#123;PROJECT_SOURCE_DIR&#125;/include ) ############################################################ # Create an executable ############################################################ # Add an executable with the above sources add_executable(hello_binary src/main.cpp ) # link the new hello_library target with the hello_binary target target_link_libraries( hello_binary PRIVATE hello::library ) 编译后在build目录下生成了libhello_library.so和可执行文件，注意在库文件删除或者移动时，程序无法执行，如何安装库文件将在之后介绍。 第三方程序引用库可以参考： target_link_libraries( hello_binary PRIVATE $&#123;PROJECT_SOURCE_DIR&#125;/build/libhello_library.so ) target_include_directories(hello_binary PRIVATE $&#123;PROJECT_SOURCE_DIR&#125;/include ) 安装大型的CMake开源软件在编译后会提供可执行文件、头文件和动态库的安装，通常安装到/usr/loacl/lib和/usr/local/bin目录中，也可以自定义安装位置，修改变量$&#123;CMAKE_INSTALL_PREFIX&#125;，像交叉编译时，一般输出到其他地方以供拷贝。 . ├── cmake-examples.conf ├── CMakeLists.txt ├── include │ └── installing │ └── Hello.h └── src ├── Hello.cpp └── main.cpp CMakeLists.txt： cmake_minimum_required(VERSION 3.5) project(cmake_examples_install) # 生成动态库 add_library(cmake_examples_inst SHARED src/Hello.cpp) target_include_directories(cmake_examples_inst PUBLIC $&#123;PROJECT_SOURCE_DIR&#125;/include) # 生成可执行文件 add_executable(cmake_examples_inst_bin src/main.cpp) target_link_libraries( cmake_examples_inst_bin PRIVATE cmake_examples_inst) #使用库 #安装可执行文件 install (TARGETS cmake_examples_inst_bin DESTINATION bin) # 安装库 install (TARGETS cmake_examples_inst LIBRARY DESTINATION lib) # 安装头文件 install(DIRECTORY $&#123;PROJECT_SOURCE_DIR&#125;/include/ DESTINATION include) # 安装配置文件 install (FILES cmake-examples.conf DESTINATION etc) 先运行一下： mkdir build install &amp;&amp; cd build cmake .. -DCMAKE_INSTALL_PREFIX=../install make &amp; make install cd ../install &amp;&amp; tree . ├── bin │ └── cmake_examples_inst_bin ├── etc │ └── cmake-examples.conf ├── include │ └── installing │ └── Hello.h └── lib └── libcmake_examples_inst.so CMake不提供卸载命令make uninstall，如果想卸载库和可执行文件，将编译生成的install_manifest.txt中的文件对应删除即可。参考Can I do “make uninstall” with CMake? 编译类型CMake支持几种编译类型：Debug，Release，MinSizeRel，RelWithDebInfo，由$&#123;CMAKE_BUILD_TYPE&#125;决定。 # Set the minimum version of CMake that can be used # To find the cmake version run # $ cmake --version cmake_minimum_required(VERSION 3.5) # Set a default build type if none was specified if(NOT CMAKE_BUILD_TYPE AND NOT CMAKE_CONFIGURATION_TYPES) message(&quot;Setting build type to &#x27;RelWithDebInfo&#x27; as none was specified.&quot;) set(CMAKE_BUILD_TYPE RelWithDebInfo CACHE STRING &quot;Choose the type of build.&quot; FORCE) # Set the possible values of build type for cmake-gui set_property(CACHE CMAKE_BUILD_TYPE PROPERTY STRINGS &quot;Debug&quot; &quot;Release&quot; &quot;MinSizeRel&quot; &quot;RelWithDebInfo&quot;) endif() # Set the project name project (build_type) # Add an executable add_executable(cmake_examples_build_type main.cpp) 默认采用的是RelWithDebInfo的编译方式，使用size工具查看不同类型的大小： size -B cmake_examples_build_type text data bss dec hex filename 2357 656 280 3293 cdd cmake_examples_build_type 比较： 类型 text data bss dec Debug 2477 664 280 3421 RelWithDebInfo 2357 656 280 3293 Release 2357 656 280 3293 MinSizeRel 2257 656 280 3193 编译标志/变量本节涉及到一个很重要的功能就是控制源码中的编译条件，我们先看C++代码： #include &lt;iostream&gt; int main(int argc, char *argv[]) &#123; std::cout &lt;&lt; &quot;Hello Compile Flags!&quot; &lt;&lt; std::endl; // only print if compile flag set #ifdef EX2 std::cout &lt;&lt; &quot;Hello Compile Flag EX2!&quot; &lt;&lt; std::endl; #endif #ifdef EX3 std::cout &lt;&lt; &quot;Hello Compile Flag EX3!&quot; &lt;&lt; std::endl; #endif return 0; &#125; 这里有两个宏EX2和EX3，它们可以由CMake决定是否定义，这是一个很强大的功能，相对也比较不容易理解。先来看下面CMakeLists.txt： cmake_minimum_required(VERSION 3.5) # 添加CXX编译控制符-DX2，缓冲CACHE类型，强制FORCE设置 set (CMAKE_CXX_FLAGS &quot;$&#123;CMAKE_CXX_FLAGS&#125; -DEX2&quot; CACHE STRING &quot;Set C++ Compiler Flags&quot; FORCE) project (compile_flags) add_executable(cmake_examples_compile_flags main.cpp) # 直接将EX3导入到C程序中 target_compile_definitions(cmake_examples_compile_flags PRIVATE EX3 ) 编译后可以看到： Hello Compile Flags! Hello Compile Flag EX2! Hello Compile Flag EX3! 这里有两种方式，一种是直接使用$&#123;CMAKE_CXX_FLAGS &#125;变量，C语言是$&#123;CMAKE_C_FLAGS&#125;，在其中不断添加新的控制符，使用-D开头，类似于命令行传递值，这时候这个标志会传递到C++程序中，表示已经定义。第二种方式是使用target_compile_definitions函数传递标志。除此之外还可以在命令行中传递： cmake .. -DCMAKE_CXX_FLAGS=&quot;-DEX2 -DEX2&quot; setset可以设置很多种类型，像BOOL、String，filepath等等，使用CACHE和FORCE时注意： SET(var1 13) 变量 var1 被设置成 13，如果 var1 在cache中已经存在，该命令不会overwrite cache中的值 SET(var1 13 ... CACHE ...) 如果cache存在该变量，使用cache中变量，如果cache中不存在，将该值写入cache SET(var1 13 ... CACHE ... FORCE) 不论cache中是否存在，始终使用该值。 上面程序中，也可以使用布尔变量来控制C++程序中的宏，让我们先感受一下set和CACHE的妙用以及复杂的CMake程序架构： . ├── build ├── CMakeLists.txt ├── config │ ├── default_config.cmake │ └── set_config.cmake ├── doc │ └── README.adoc └── src └── main.cpp .cmake文件通常是CMake的配置文件，你可以认为这是CMake的头文件，定义变量和规则或者函数通常都可以放在这类文件中。它们可以通过include函数在CMakeLists.txt中引入，程序默认在$&#123;CMAKE_MODULE_PATH&#125;下搜索此文件。作用域是从导入点到后面的CMake程序，导入点之前无法使用其中的值或者函数。先看一下CMakeLists.txt： cmake_minimum_required(VERSION 3.5) project (compile_flags) add_executable(cmake_examples_compile_flags src/main.cpp) include(config/set_config.cmake) include(config/default_config.cmake) 比较简单，先为程序添加可执行文件的目标，然后在set_config中： # if(EX2) # target_compile_definitions(cmake_examples_compile_flags # PRIVATE EX2 # ) # endif() # if(EX3) # target_compile_definitions(cmake_examples_compile_flags # PRIVATE EX3 # ) # endif() target_compile_definitions(cmake_examples_compile_flags PRIVATE $&lt;$&lt;BOOL:$&#123;EX2&#125;&gt;:EX2&gt; $&lt;$&lt;BOOL:$&#123;EX3&#125;&gt;:EX3&gt; ) 这里使用两种方法导入标志，第一种是if的写法，第二种是表达式写法，相对第二种简单但可读性稍差，尤其是当组合变量的表达式变得复杂时，需要格外小心。表达式采用NOT、AND、OR的组合，或者数值运算&gt;，&lt;，或=，以及STRING的equals等等。这个之后再补充介绍。 最后是引入default_config.cmake中默认的值，即命令行没有输入时，两个变量选择的值。注意如果之前CACHE中已经有设置这个值，比如ON，默认的值CACHE设置不会Over Write这个变量，除非使用FORCE。这是CACHE带来的不便,，但从另一方面来说，这也方便不需要重复运行cmake指令。 set(EX2 OFF CACHE BOOL &quot;EX2&quot;) set(EX3 OFF CACHE BOOL &quot;EX3&quot;) 因为是布尔值，所以编译时参数应当设置为ON/OFF或者True/False。如果没有输入，则默认OFF/False。 cmake .. -DEX3=ON -DEX2=ON make &amp;&amp; ./cmake_examples_compile_flags Hello Compile Flags! Hello Compile Flag EX2! Hello Compile Flag EX3! 注意如果此时继续cmake ..不输入任何变量，缓存中这两个仍然是打开的，除非删除build重新编译或者输入-DEX3=OFF -DEX2=OFF或者对缓存中的变量进行修改。在CMakeCache.txt中可以找到： //EX2 EX2:BOOL=ON //EX3 EX3:BOOL=ON 可以手动修改CACHE中的值，然后重新编译，比如这里设置EX2:BOOL=OFF，重新make后，EX2所控制的输出将被静默。 有关CMake set的CACHE set和Normal set还可以参考：cmake cache变量 第三方库我们的程序常常使用第三方库，例如现在我们有一个程序要使用Mbedtls的库和函数，一种方法是我们在系统中安装mbedtls的库和头文件，然后程序编译时链接，这其实和GCC使用默认的库是一回事；另一种方法我们下载源码，并将源码放在我们的工程当中，再进行编译。让我们来手动一步步尝试实现。 安装并使用首先下载mbedtls并编译安装： git clone https://github.com/ARMmbed/mbedtls.git cd mbedtls &amp;&amp; mkdir build &amp;&amp; cd build cmake .. &amp;&amp; make -j32 &amp;&amp; sudo make install 然后我们新建一个目录： . ├── build ├── CMakeLists.txt ├── include │ ├── mbedtls # mbedtls头文件 │ ├── psa # psa头文件 │ └── mbedtls_config.h # 配置文件 └── src └── main.c CMakeLists.txt文件： cmake_minimum_required(VERSION 3.8) project(&quot;hash&quot;) add_executable(hash src/main.c) target_include_directories(hash PUBLIC $&#123;PROJECT_SOURCE_DIR&#125;/include ) target_link_libraries(hash PUBLIC mbedtls mbedcrypto # 直接使用libmbedcrypto.a库文件，在系统目录下 ) main.c是一个单向散列函数计算的源码： #include &lt;stdio.h&gt; #include &lt;string.h&gt; #include &lt;stdint.h&gt; #include &quot;mbedtls/md.h&quot; #include &quot;mbedtls/platform.h&quot; static void dump_buf(char *info, uint8_t *buf, uint32_t len) &#123; mbedtls_printf(&quot;%s&quot;, info); for (int i = 0; i &lt; len; i++) &#123; mbedtls_printf(&quot;%s%02X%s&quot;, i % 16 == 0 ? &quot;
	&quot;:&quot; &quot;, buf[i], i == len - 1 ? &quot;
&quot;:&quot;&quot;); &#125; mbedtls_printf(&quot;
&quot;); &#125; int main(void) &#123; uint8_t digest[32]; char *msg = &quot;abc&quot;; mbedtls_md_context_t ctx; const mbedtls_md_info_t *info; mbedtls_md_init(&amp;ctx); info = mbedtls_md_info_from_type(MBEDTLS_MD_SHA256); mbedtls_md_setup(&amp;ctx, info, 0); mbedtls_printf(&quot;
 md info setup, name: %s, digest size: %d
&quot;, mbedtls_md_get_name(info), mbedtls_md_get_size(info)); mbedtls_md_starts(&amp;ctx); mbedtls_md_update(&amp;ctx, msg, strlen(msg)); mbedtls_md_finish(&amp;ctx, digest); dump_buf(&quot;
 md sha-256 digest:&quot;, digest, sizeof(digest)); mbedtls_md_free(&amp;ctx); return 0; &#125; 配置头文件mbedtls_config.h： /* System support */ #define MBEDTLS_PLATFORM_C #define MBEDTLS_PLATFORM_MEMORY #define MBEDTLS_MEMORY_BUFFER_ALLOC_C #define MBEDTLS_PLATFORM_NO_STD_FUNCTIONS #define MBEDTLS_PLATFORM_EXIT_ALT #define MBEDTLS_NO_PLATFORM_ENTROPY #define MBEDTLS_NO_DEFAULT_ENTROPY_SOURCES #define MBEDTLS_PLATFORM_PRINTF_ALT /* mbed TLS modules */ #define MBEDTLS_BIGNUM_C #include &quot;mbedtls/check_config.h&quot; 这样编译运行： ./hash md info setup, name: SHA256, digest size: 32 md sha-256 digest: BA 78 16 BF 8F 01 CF EA 41 41 40 DE 5D AE 22 23 B0 03 61 A3 96 17 7A 9C B4 10 FF 61 F2 00 15 AD 直接下载并使用这里借用git工具远程下载并使用。参考：git_repository . ├── build ├── CMakeLists.txt ├── config │ └── config.cmake ├── include │ └── mbedtls_config.h ├── lib │ └── CMakeLists.txt └── src └── main.c 先看一下根目录的CMakeLists.txt： cmake_minimum_required(VERSION 3.8) project(&quot;hash&quot;) # 导入MBEDTLS第三方库信息 include(config/config.cmake) # 下载MBEDTLS库，路径保存在 MBEDCRYPTO_PATH 中 add_subdirectory($&#123;PROJECT_SOURCE_DIR&#125;/lib) # 添加库的所有源码 aux_source_directory($&#123;MBEDCRYPTO_PATH&#125;/library MBEDTLS_SOURCES) # 建立可执行文件目标 add_executable(hash $&#123;CMAKE_CURRENT_LIST_DIR&#125;/src/main.c $&#123;MBEDTLS_SOURCES&#125; ) # 添加头文件 target_include_directories(hash PUBLIC $&#123;PROJECT_SOURCE_DIR&#125;/include $&#123;MBEDCRYPTO_PATH&#125;/include $&#123;MBEDCRYPTO_PATH&#125;/library ) 第一步导入config.cmake中关于Mbedtls相关的变量，指定了远程的位置和版本： set(MBEDCRYPTO_PATH &quot;DOWNLOAD&quot; CACHE PATH &quot;Path to Mbed Crypto (or DOWNLOAD to fetch automatically&quot;) set(MBEDCRYPTO_VERSION &quot;mbedtls-3.0.0&quot; CACHE STRING &quot;The version of Mbed Crypto to use&quot;) set(MBEDCRYPTO_GIT_REMOTE &quot;https://github.com/ARMmbed/mbedtls.git&quot; CACHE STRING &quot;The URL (or path) to retrieve MbedTLS from.&quot;) set(MBEDCRYPTO_BUILD_TYPE &quot;$&#123;CMAKE_BUILD_TYPE&#125;&quot; CACHE STRING &quot;Build type of Mbed Crypto library&quot;) set(TFM_MBEDCRYPTO_CONFIG_PATH &quot;$&#123;CMAKE_SOURCE_DIR&#125;/include/mbedtls_config.h&quot; CACHE PATH &quot;Config to use for Mbed Crypto&quot;) 然后lib/CMakeLists.txt再根据输入和默认值判断是否要下载第三方库，借助FetchContent工具来引入第三方GIT下载源码。 include(FetchContent) set(FETCHCONTENT_QUIET FALSE) if (&quot;$&#123;MBEDCRYPTO_PATH&#125;&quot; STREQUAL &quot;DOWNLOAD&quot;) find_package(Git) FetchContent_Declare(mbedcrypto GIT_REPOSITORY $&#123;MBEDCRYPTO_GIT_REMOTE&#125; GIT_TAG $&#123;MBEDCRYPTO_VERSION&#125; GIT_SHALLOW TRUE GIT_PROGRESS TRUE GIT_SUBMODULES &quot;&quot; ) FetchContent_GetProperties(mbedcrypto) if(NOT mbedcrypto_POPULATED) FetchContent_Populate(mbedcrypto) set(MBEDCRYPTO_PATH $&#123;mbedcrypto_SOURCE_DIR&#125; CACHE PATH &quot;Path to mbed-crypto (or DOWNLOAD to get automatically&quot; FORCE) endif() endif() 如果已经下载过mbedtls，可以在命令行手动输入-DMBEDCRYPTO_PATH，这样CMake将不会自动下载目录。编译过程： cmake .. -- The C compiler identification is GNU 9.3.0 -- The CXX compiler identification is GNU 9.3.0 -- Detecting C compiler ABI info -- Detecting C compiler ABI info - done -- Check for working C compiler: /usr/bin/cc - skipped -- Detecting C compile features -- Detecting C compile features - done -- Detecting CXX compiler ABI info -- Detecting CXX compiler ABI info - done -- Check for working CXX compiler: /usr/bin/c++ - skipped -- Detecting CXX compile features -- Detecting CXX compile features - done -- Found Git: /usr/bin/git (found version &quot;2.25.1&quot;) -- Populating mbedcrypto -- Configuring done -- Generating done -- Build files have been written to: /home/sjl/learn/cmake-examples/mbedtls_test/build/_deps/mbedcrypto-subbuild Scanning dependencies of target mbedcrypto-populate [ 11%] Creating directories for &#x27;mbedcrypto-populate&#x27; [ 22%] Performing download step (git clone) for &#x27;mbedcrypto-populate&#x27; Cloning into &#x27;mbedcrypto-src&#x27;... remote: Enumerating objects: 20471, done. remote: Counting objects: 100% (20471/20471), done. remote: Compressing o