除定时器任务自身 &#125; 多内核对象测试使用内核对象集合进行统一处理，具体实现方式在创建队列、互斥等对象后，将对象放入集合并在一个任务中统一处理： /********************************** 内核对象句柄 *******************************/ static SemaphoreHandle_t xSemaphore = NULL; static xQueueHandle xQueue1 = NULL; static xQueueHandle xQueue2 = NULL; static xQueueSetHandle xQueueSet = NULL; /********************************** 任务函数定义 *******************************/ static void vTaskStart( void * pvParameters ) //起始任务 &#123; ...... /* 创建二值信号量 */ xSemaphore = xSemaphoreCreateBinary(); //按键信号量 /* 创建两个消息队列 */ xQueue1 = xQueueCreate( 10, sizeof(uint32_t) ); //消息队列1 xQueue2 = xQueueCreate( 10, sizeof(uint32_t) ); //消息队列2 /* 创建一个内核对象集合 */ xQueueSet = xQueueCreateSet( 1 ); /* 添加内核对象到对象集合 xQueueSet */ xQueueAddToSet(xSemaphore, xQueueSet); xQueueAddToSet(xQueue1, xQueueSet); xQueueAddToSet(xQueue2, xQueueSet); ...... &#125; static void vTaskPend(void *pvParameters) &#123; QueueSetMemberHandle_t xActivatedMember; uint32_t ulQueueMsgValue; uint8_t ucQueueMsgValue; while(1) &#123; /* 等待多个内核对象 */ xActivatedMember = xQueueSelectFromSet(xQueueSet, portMAX_DELAY); /* 判断接收哪个内核对象 */ if(xActivatedMember == xQueue1) //如果接收到的对象是xQueue1 &#123; /* 接收xQueue1的消息 */ xQueueReceive(xActivatedMember, &amp;ulQueueMsgValue, 0); printf(&quot;接收到消息队列1接收到消息内容为 %d
