&#x27;) json++; /* double-slash comments, to end of line. */ else if (*json==&#x27;/&#x27; &amp;&amp; json[1]==&#x27;*&#x27;) &#123;while (*json &amp;&amp; !(*json==&#x27;*&#x27; &amp;&amp; json[1]==&#x27;/&#x27;)) json++;json+=2;&#125; /* multiline comments. */ else if (*json==&#x27;\&quot;&#x27;)&#123;*into++=*json++;while (*json &amp;&amp; *json!=&#x27;\&quot;&#x27;)&#123;if (*json==&#x27;\&#x27;) *into++=*json++;*into++=*json++;&#125;*into++=*json++;&#125; /* string literals, which are \&quot; sensitive. */ else *into++=*json++; /* All other characters. */ &#125; *into=0; /* and null-terminate. */ &#125; CJSON主要数据结构如下，采用双向链表的形式： typedef struct cJSON &#123; struct cJSON *next,*prev; /* 遍历数组或对象链的前向或后向链表指针*/ struct cJSON *child; /*数组或对象的孩子节点*/ int type; /* key的类型*/ char *valuestring; /*字符串值*/ int valueint; /* 整数值*/ double valuedouble; /* 浮点数值*/ char *string; /* key的名字*/ &#125; cJSON; cJSON是使用链表来存储数据的，其访问方式很像一颗树。每一个节点可以有兄弟节点，通过next/prev指针来查找，它类似双向链表；每个节点也可以有孩子节点，通过child指针来访问，进入下一层。只有节点是对象或数组时才可以有孩子节点。 type是键（key）的类型，一共有7种取值，分别是：False，Ture，NULL，Number，String，Array，Object。 若是Number类型，则valueint或valuedouble中存储着值。若期望的是int，则访问valueint，若期望的是double，则访问valuedouble，可以得到值。 若是String类型的，则valuestring中存储着值，可以访问valuestring得到值。 string中存放的是这个节点的名字，可理解为key的名称。 接口函数重要的接口函数： **1. cJSON cJSON_Parse(const char value);解析JSON数据包，并按照cJSON结构体的结构序列化整个数据包。可以看做是获取一个句柄。**2. cJSON *cJSON_GetObjectItem(cJSON object,const char string);功能：获取json指定的对象成员参数：*objec：第一个函数中获取的句柄。string：需要获取的对象返回值：这个对象成员的句柄 如果json格式的对象成员直接就是字符串那么就可以直接通过结构体中的valuestring元素来获取这个成员的值**3. cJSON cJSON_GetArrayItem(cJSON array,int item);功能：有可能第二个函数中获取到的是成员对象值是一个数组，那么就需要用到这个函数。用来获取这个数组指定的下标对象参数：*array：传入第二步中返回的值，item：想要获取这个数组的下标元素返回值：这个数组中指定下标的对象。然后在对这个返回值重复使用第二步函数就可以获取到各个成员的值了。也就是说对象是数组的比是字符串的要多用一个cJSON_GetArrayItem函数，其他的没区别。4. cJSON_Delete()用来释放你第一步获取的句柄，来释放整个内存。用在解析完后调用 读一层配置文件&#123; &quot;spidev1&quot;: &#123; &quot;device_name&quot;: &quot;spidev1&quot;, &quot;speed&quot;: &quot;150000&quot;, &quot;mode&quot;: &quot;0&quot;, &