&quot;, (int)atoi(item-&gt;valuestring)); cJSON_Delete(root); fclose(fp); &#125; &#125; 读两层配置文件&#123; &quot;奔驰&quot;: &#123; &quot;factory&quot;: &quot;一汽大众&quot;, &quot;last&quot;: 31, &quot;price&quot;: 83, &quot;sell&quot;: 49, &quot;sum&quot;: 80, &quot;other&quot;: [123, 1, &quot;hello, world&quot;, &#123; &quot;梅斯德斯奔驰&quot;: &quot;心所向, 持以恒&quot; &#125;] &#125; &#125; #include &lt;stdio.h&gt; #include &lt;string.h&gt; #include &quot;cJSON.h&quot; int main() &#123; FILE* fp = fopen(&quot;car.json&quot;, &quot;r&quot;); char buf[1024] = &#123;0&#125;; fread(buf, 1, sizeof(buf), fp); cJSON* root = cJSON_Parse(buf); cJSON* subobj = cJSON_GetObjectItem(root,&quot;奔驰&quot;); if(subobj)&#123; // 获取子对象 cJSON* fasctory = cJSON_GetObjectItem(subobj,&quot;factory&quot;); cJSON* last = cJSON_GetObjectItem(subobj,&quot;last&quot;); cJSON* price = cJSON_GetObjectItem(subobj, &quot;price&quot;); cJSON* sell = cJSON_GetObjectItem(subobj,&quot;sell&quot;); cJSON* sum = cJSON_GetObjectItem(subobj,&quot;sum&quot;); cJSON* other = cJSON_GetObjectItem(subobj,&quot;other&quot;); // 打印value的值 printf(&quot;奔驰: 
