元素的迭代器 lower_bound 返回关键字不小于k的第一个元素的迭代器 begin()/rbegin() 迭代器第一个位置 end()/rend() 迭代器最后一个位置 set&lt;int&gt; s; set&lt;int&gt;::iterator it; s.insert(1); s.insert(2); s.insert(14); s.insert(3); s.insert(4); s.insert(4); for (it = s.begin(); it != s.end(); it++) &#123; cout &lt;&lt; *it &lt;&lt; &quot; &quot;; &#125; cout &lt;&lt; endl; if (s.find(13) == s.end()) &#123; cout &lt;&lt; &quot;cannot find 13 in s&quot; &lt;&lt;endl; &#125; if (s.count(15) == 0) &#123; cout &lt;&lt; &quot;cannot find 15 in s&quot; &lt;&lt;endl; &#125; multiset&lt;int&gt; ms; multiset&lt;int&gt;::iterator mit; ms.insert(1); ms.insert(2); ms.insert(14); ms.insert(3); ms.insert(4); ms.insert(4); for (mit = ms.begin(); mit != ms.end(); mit++) &#123; cout &lt;&lt; *mit &lt;&lt; &quot; &quot;; &#125; cout &lt;&lt; endl; 对于set s，4只能插入一次，对于multiset ms，4可以插入多次： 1 2 3 4 14 cannot find 13 in s cannot find 15 in s 1 2 3 4 4 14 map/multimap map的底层是红黑树，使用pair对进行插入，亦可以直接map[key] = value插入，默认按照key的升序进行存放； map不允许key多次出现，而multimap是允许的，但不支持[]快速访问 查找可以用count也可以用find； 方法 描述 empty() 判断是否为空映射 size() 返回映射中元素个数 insert() 参考下面代码 map[key] 既可以返回key的value，也可以插入key和value find() 与set类似，不存在则返回end()的迭代器 count() 返回key的元素个数，map为0/1 // map[key , value], key = map-&gt;first, value = map-&gt;second map&lt;char, int&gt; mymap; mymap.insert(pair&lt;char, int&gt;(&#x27;a&#x27;, 1)); //插入方式1 mymap.insert(map&lt;char, int&gt;::value_type(&#x27;b&#x27;, 2)); //插入方式2 mymap[&#x27;c&#x27;] = 3; //插入方式3 map&lt;char, int&gt;::iterator it; for (it = mymap.begin(); it != mymap.end(); it++) &#123; cout &lt;&lt; &quot;[&quot; &lt;&lt; it-&gt;first &lt;&lt; &quot;,&quot; &lt;&lt; it-&gt;second &lt;&lt; &quot;]&quot; &lt;&lt; endl; &#125; for (it = mymap.begin(); it != mymap.end(); it++) &#123; cout &lt;&lt; mymap[it-&gt;first] &lt;&lt; endl; &#125; if (mymap.find(&#x27;d&#x27;) == mymap.end()) &#123; cout &lt;&lt; &quot;cannod find d in mymap&quot; &lt;&lt; endl; &#125; if (mymap.count(&#x27;e&#x27;) == 0)&#123; cout &lt;&lt; &quot;cannod find e in mymap&quot; &lt;&lt; endl; &#125; [a,1] [b,2] [c,3] 1 2 3 cannod find d in mymap cannod find e in mymap unordered_map/unordered_set

