=0) return NULL; int all,num=preorderSize;//标记先序数组第一个元素在中序数组位置 struct TreeNode* node=malloc(sizeof(struct TreeNode)); node-&gt;val=preorder[0]; //匹配preorder[0]在inorder的下标 while(num--) &#123; if(inorder[num]==preorder[0])&#123; break; &#125; &#125; all=num+1; node-&gt;left=buildTree(preorder+1,num,inorder,num); node-&gt;right=buildTree(preorder+all,preorderSize-all,inorder+all,inorderSize-all); return node; &#125;

